fixed_code:
extern crate bumpalo;

use bumpalo::Bump;

#[derive(Debug)]
enum Shape {
    Circle(f64),
    Rectangle { width: f64, height: f64 }
}

fn process_shape<'a>(arena: &'a Bump, shape: &Shape) -> String {
    match *shape {
        Shape::Circle(_) => "Circle".to_string(),
        Shape::Rectangle { .. } => "Rectangle".to_string(),
    }
}

fn main() {
    let arena = Bump::new();
    let circle = arena.alloc(Shape::Circle(3.0));
    println!("{}", process_shape(&arena, circle));
}

